def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    for c in range(1, b + 4):
                        factor = ((ratio - a) ** 7) / (a * b * c * 1.1 + 1)
                        priority += factor * np.sin(ratio * c / (b + 1)) * np.cos(ratio * b / (a + 2))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
            if bin_cap < item * 0.9:
                priority += np.sqrt(item * bin_cap) * np.tanh(ratio)
            else:
                priority -= np.log(bin_cap + 2) * 3
        elif 5 < ratio <= 8:
            s = 0
            for p in range(1, int(np.floor(ratio)) + 5):
                for q in range(1, p + 4):
                    k = ((ratio - p) ** 4) * np.sin(ratio * q) / (q + 0.7)
                    s += np.tanh(k) * 1.7
            priority = s + np.log(ratio + 1) * 11 - np.tanh(ratio - 5) * 3
            for d in range(2, 6):
                if (i + d) % 5 == 0:
                    priority += np.sin(ratio * d * i) * 0.5
                else:
                    priority -= np.cos(ratio * d * i) * 0.4
        elif 2.5 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for r in range(1, 15):
                s1 += ((ratio - 2.5) ** r) / (r * 2.2) * np.cos(r * ratio * 0.9)
            for t in range(1, 7):
                s2 += ((5 - ratio) ** t) / (t * 1.9) * np.sin(t * ratio * 1.1)
            priority = (s1 * np.cos(8 * ratio)) - np.log(ratio + 0.5) * 7 + np.tanh(5 - ratio) * 2 + s2 * 0.4
            if bin_cap < item * 0.75:
                priority += np.exp(-ratio) * 4
            else:
                priority -= np.sqrt(bin_cap / (item + 1)) * 3
        elif 1.0 <= ratio < 2.5:
            s = 0
            for n in range(1, 12):
                s += ((2.5 - ratio) ** n) / (n ** 2 + 1) * np.sin(n * ratio)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.exp(-item / (bin_cap + 0.1)) * 3
            else:
                penalty = np.cos(15 * ratio) * 3.5
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1.0) ** m) / m
            if (i + int(item * 2.2)) % 6 == 0:
                priority *= np.log1p(bin_cap) * 1.5
        elif 0.5 <= ratio < 1.0:
            s = 0
            for u in range(1, 18):
                s += ((1.0 - ratio) ** u) / (u * 3.8) * np.cos(u * ratio * 1.5)
            priority = s
            if (i * int(item * 1.7)) % 5 == 0:
                priority *= np.sqrt(bin_cap + 4) * 2
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for j in range(1, 8):
                priority += ((1.0 - ratio) ** j) * np.sin(j * item * 1.7) * 0.9
            if bin_cap < item * 0.5:
                priority += np.tanh(bin_cap / (item + 1)) * 5
        elif 0.15 <= ratio < 0.5:
            s = 0
            for w in range(1, 20):
                s += ((0.5 - ratio) ** w) / (w * 5) * np.sin(w * ratio * 3)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 1.7) % 7 == 0:
                priority *= 3
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
                for z in range(1, 5):
                    priority += ((0.5 - ratio) ** z) / (z * 4) * np.cos(item * z * 1.5)
            elif bin_cap > item * 1.5:
                priority -= np.exp(-ratio * 2.5) * 5
        else:
            s = 0
            for v in range(1, 15):
                s += ((0.15 - ratio) ** v) / (v * 6) * np.cos(v * item * 1.0)
            priority = s + 4 / (bin_cap + 6)
            if int(item * 1.1) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for y in range(1, 10):
                priority += ((0.15 - ratio) ** y) / (y * 8) * np.sin(item * y * 0.95)
        if bin_cap < item * 0.4:
            priority += np.log1p(item ** 3 * bin_cap) * 7
            for aa in range(1, 5):
                if (i + aa) % 4 == 0:
                    priority += np.sin(ratio * (i + aa) * 1.3) * 0.4
                else:
                    priority -= np.cos(ratio * (i + aa) * 1.3) * 0.4
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
            for bb in range(1, 6):
                if (i + bb) % 5 == 0:
                    priority += np.sin(ratio * (i + bb) * 0.9) * 0.5
                else:
                    priority -= np.cos(ratio * (i + bb) * 0.9) * 0.5
        for cc in range(1, 5):
            if (i + cc * 2) % 6 == 0:
                priority += np.sin(ratio * (i + cc * 2)) * 0.35
            else:
                priority -= np.cos(ratio * (i + cc * 2)) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        priorities[i] = priority
    return priorities
